class Sub final : public detail::Handle {
public:
	Sub() = default;
	explicit Sub(uint64_t h) : detail::Handle(h) {}
	/* closes (unsubscribes) on destruction, like a scoped connection */
	~Sub() {
		if (h_) {
			urnet_sub_close(h_);
		}
	}
	Sub(Sub&&) = default;
	Sub& operator=(Sub&& o) noexcept {
		if (this != &o && h_) {
			urnet_sub_close(h_);
		}
		detail::Handle::operator=(std::move(o));
		return *this;
	}
	void close() const;
};

